SELECT DISTINCT i.institution_name
FROM institutional_data i
JOIN phd_awards pa ON i.institution_id = pa.institution_id;

SELECT year, n_phds
FROM phd_awards
ORDER BY year ASC;

SELECT year, SUM(n_phds) AS total_phds
FROM phd_awards
GROUP BY year;

SELECT research_topic
FROM phd_awards
WHERE year = 2022 AND ethnicity = 'Asian';

SELECT COUNT(*)
FROM phd_awards
WHERE year = 2020 AND institution_id = 1;

SELECT COUNT(phd_id) AS number_of_phds
FROM phd_awards
WHERE year = 2020;

SELECT total_phds
FROM institutional_data
WHERE institution_name = 'University of Agriculture';

SELECT id.institution_name, id.total_phds
FROM institutional_data id
WHERE id.total_phds > (
    SELECT AVG(total_phds) FROM institutional_data
);

SELECT DISTINCT year
FROM phd_awards
ORDER BY year ASC;

SELECT broad_field_name
FROM broad_fields
LIMIT 1;
